INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$ffe10fe9-10b5-6482-011c-870c828c539d$X$,$X$7b60f6dd-e623-3f77-3f1a-c1fae1b1e05c$X$,$X$Article 4$X$,$X$MFSA Annual Supervisory Fee$X$,$X$For revenue up to €250,000, the Company is liable to pay the €6,000 Fixed Element fee. Further tranches of €250,000 up to a maximum of €50m, the Company is liable to pay the Variable Element fee of €400 per tranche or part thereof.$X$,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$2af7313f-aafd-c502-0706-a9e385fc9bbc$X$,$X$7bdfc2b2-d9ab-1cf2-e024-7fe03ef880c5$X$,$X$General$X$,$X$MFSA NRF Annual Contribution$X$,$X$103.(1)  In  order  to  reach  the  target  level  specified  in  Regulation 102, contributions shall be raised at least annually from the institutions licensed in Malta including Union branches.
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$379686a2-5e93-4b3f-9676-a10570610abc$X$,$X$3aefee06-1d17-b248-4ae5-eb364ac60226$X$,$X$General$X$,$X$SME Calculation$X$,$X$Financial Institutions are required to establish and classify their organization size as one of the following:
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$9e702ece-0ad3-4f5e-78a5-668ec6697c1a$X$,$X$16323495-2ba0-3eed-d3d0-6d5ced568912$X$,$X$General$X$,$X$SME Calculation$X$,NULL,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$fe60240d-fe69-d709-8bd8-64e69988849a$X$,$X$9ebc7955-ab3a-f0e2-ca2c-c563bba055ed$X$,$X$General$X$,$X$Quarterly Monitoring CFD loss %$X$,$X$FYI re LPs - In accordance with the MFSA 2022 Inspection:
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$85d117cb-add5-b511-c536-eb4e9a1e38f5$X$,$X$1d9e968a-67e1-94f5-419a-dcc4b96de175$X$,$X$Chapter 1 Disclosures, Article R.1.2.75$X$,$X$Annual CFD Loss % Query Check by Quants$X$,$X$"The risk warning shall include an up-to-date specific loss percentage which is specific to the Regulated Person and which is based on a calculation of the percentage of CFD trading accounts provided to retail clients by the Regulated Person that lost money. The calculation shall be performed every three months and shall cover the 12 month period preceding the date on which it is performed (“12 month calculation period”). For the purposes of th calculation:
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$0e4d5127-a14a-4e64-7abf-b6893bb2d1a9$X$,$X$c82c0b30-a111-36c2-7df5-5d689c6581a9$X$,$X$Article R.1.1.13$X$,$X$Quarterly Monitoring of Website Disclosures$X$,$X$"Where a Regulated Person communicates with a Client by means of a website, it must ensure that it has in place appropriate arrangements in order to record all the specific Information disclosed to the Client by means of its website, including dated logs of such disclosures, in order to demonstrate that it has complied with all its regulatory requirements".$X$,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$6fe6a5df-53ed-1b8f-f9db-26cd50c9dc4b$X$,$X$1d9e968a-67e1-94f5-419a-dcc4b96de175$X$,$X$Chapter 1 Disclosures, Article R.1.6.5$X$,$X$Annual Key Information Documents (KIDs) Reviews [H1]$X$,$X$The Key Information Document shall constitute pre-contractual information. It shall be accurate, fair, clear and not misleading. It shall provide key information and shall be consistent with any binding contractual documents, with the relevant parts of the offer documents and with the terms and conditions of the PRIIP. The Key Information Document shall be a stand-alone document, clearly separate from marketing materials. It shall not contain cross-references to marketing material. It may contain cross-references to other documents including a prospectus where applicable, and only where the cross reference is related to the information required to be included in the Key Information Document.$X$,1,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$686cd85e-5510-5533-ea3a-beae2d674cb6$X$,$X$1d9e968a-67e1-94f5-419a-dcc4b96de175$X$,$X$Chapter 1 Disclosures, Article R.1.6.16$X$,$X$Annual Key Information Documents (KIDs) Reviews [H1]$X$,$X$"The PRIIP Manufacturer must review the information contained in the Key Information Document on a regular basis and must review the information every time there is a change that significantly affects or is likely to significantly affect the information contained in the Key Information Document and, at least, every twelve months following the date of the initial publication of the Key Information Document".$X$,2,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$734c511c-ccf1-eaab-5cd4-d062a45293b2$X$,$X$00d8bdc7-7be0-a366-ea39-2d67514b4d19$X$,$X$General$X$,$X$Quarterly Monitoring Client Statements$X$,$X$R.1.4.41: Where a Regulated Person has executed an order, other than for Portfolio Management, on behalf of a Client, it shall in respect of that order:
(a) promptly provide the Client, in a Durable medium, with the essential Information concerning the execution of that order;
(b) send a notice to the Client in a Durable medium confirming execution of the order as soon as possible and no later than the first business day following execution or, where the confirmation is received by the Regulated Person from a third party, no later than the first business day following receipt of the confirmation from the third party;
(c) in the case of Eligible counterparties, Regulated Persons shall be allowed to enter into agreements with such counterparties to determine content and timing of reporting which are different from those applicable to Retail and Professional Clients"".
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$32cfd752-e9ef-31f7-1f35-ba0b4f443bc5$X$,$X$672881b9-7de0-76ce-482b-8327d0186121$X$,$X$R.1.4.56 (Quarterly Statements)$X$,$X$Quarterly Monitoring Client Statements$X$,$X$A Regulated Person that holds Client Financial Instruments or Client money shall send at least on a quarterly basis , to each Client for whom it holds Financial Instruments or funds, a statement in a Durable medium of those Financial Instruments or funds unless such a statement has been provided in any other periodic statement. Such statements shall be provided more frequently on Client request at commercial costs.$X$,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$6e13bd4b-87af-1af9-e70e-a3a1f54fe85d$X$,$X$97660951-c404-0c03-1151-38e50c7493e4$X$,$X$General$X$,$X$Annual Monitoring of EU/National Sustainability Regulations Applicability$X$,$X$(CSRD),$X$,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$71ec94cc-8b77-0161-95a2-f1a229f418da$X$,$X$e88fb592-0785-1c2e-05c7-10ce7521c400$X$,$X$General$X$,$X$Annual Monitoring of EU/National Sustainability Regulations Applicability$X$,$X$(ESRS), and$X$,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$b1dece3d-8811-27b3-05c2-63c6b9295b3d$X$,$X$a42b4975-2a96-f246-a7bd-739146a196e3$X$,$X$General$X$,$X$Annual Monitoring of EU/National Sustainability Regulations Applicability$X$,$X$(SFDR) and$X$,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$ab07d4a4-9caa-4ac5-7e7d-de02710ffa6c$X$,$X$af61511a-3ba1-93f5-1a08-e80e890c4a89$X$,$X$General$X$,$X$Annual Monitoring of EU/National Sustainability Regulations Applicability$X$,$X$(NFRD)$X$,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$b25a6281-6598-dd53-4ca5-5db20a3cd70a$X$,$X$2f78fca5-e06e-4b86-ce96-27c9de424c9b$X$,$X$General$X$,$X$Annual Monitoring of EU/National Sustainability Regulations Applicability$X$,$X$(Section 4 Corporate Culture, CSR and ESG)
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$88f7ddf6-b578-5934-33ac-9c08b78454e3$X$,$X$9de4d4ca-8044-1bea-7f85-688f96cb6f67$X$,$X$General$X$,$X$Annual Review of ESG Strategy$X$,$X$Entities should have a ESG strategy in place and should adequately report on ESG initiatives.$X$,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$9bf2af30-0242-c3a5-cef6-ede291de4950$X$,$X$4e169dd0-28b1-c415-0be1-dce6bee0546f$X$,$X$Section 7 Annual Review$X$,$X$Annual Report on ESG Strategy$X$,$X$The Board of Directors conducts an annual strategic review of the ESG Strategy, examining overall performance against established objectives, effectiveness of implementation, and alignment with evolving regulatory requirements and market practices. This high-level assessment ensures our strategy remains robust and forward-looking while meeting stakeholder expectations.$X$,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$03ffcb66-e2b6-6435-0ab1-5a8c3f421208$X$,$X$17280db9-4151-d025-99ef-310907a9ed4c$X$,$X$R2-3.1.1.2 & R1-1.23.2$X$,$X$Annual Review Whisteblowing Policy
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$5b37b23d-713f-d2ad-a1eb-6e9e49086c30$X$,$X$e7542e68-93c6-b9a2-0c5e-26716903315f$X$,$X$General$X$,$X$Annual Review Whisteblowing Policy
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$a26467fe-f7ab-c399-2fdb-62925ab85510$X$,$X$17280db9-4151-d025-99ef-310907a9ed4c$X$,$X$Section 2 Audited Annual Reporting Requirements
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$217e5233-155a-0b82-f40b-4c76438039f3$X$,$X$17280db9-4151-d025-99ef-310907a9ed4c$X$,$X$R1-2.2.4$X$,$X$Annual MFSA Remedial Action Taken on Auditors' Management Letter$X$,$X$Pursuant to Rule R1-2.2.1(iii), the Licence Holder in receipt of a management letter from its auditor which contains recommendations to remedy any weakness identified during the course of the audit, is required to submit to the MFSA by not later than six months from the end of the financial period to which the management letter relates, a statement setting out in detail the manner in which the auditor’s recommendations have been/are being implemented. In the instance where the Licence Holder has not taken/is not taking any action in respect of any one or more recommendations in the auditor’s management letter, the reasons are to be included.$X$,2,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$143db65c-a5c9-4586-d263-7b8275ad33b5$X$,$X$17280db9-4151-d025-99ef-310907a9ed4c$X$,$X$Section 12 System certification  
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$2253acf1-2c84-e30c-38b4-ac08f57b5040$X$,$X$17280db9-4151-d025-99ef-310907a9ed4c$X$,$X$Section Risk
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$366eeae7-05ff-4ff6-a8a3-f10336d9d081$X$,$X$17280db9-4151-d025-99ef-310907a9ed4c$X$,$X$R3-3.1.2.5 (iii), R1-1.8.13, R2-3.2.12 (i), R2-3.4.1$X$,$X$Annual Review Accounting Procedures 
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$00dec7b9-8539-3eff-debe-9286e167dca0$X$,$X$e8a7f3e8-f593-2c35-4a56-fccc6406da04$X$,$X$General$X$,$X$Annual Review of Board Terms of Reference$X$,$X$The Board should clearly define its remit and power in a written document which is approved by the Board, e.g., a Board Charter or Board Terms of Reference and ensure that this is known by all of the entity. Likewise, the remit and powers of the Senior Management should be outlined in a similar document.$X$,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$c3606194-2500-3052-28a9-50dd66f62647$X$,$X$a0f8fe7b-aa62-5bb5-96f6-ab442f2a9599$X$,$X$General$X$,$X$Annual Review of Succession Plan$X$,$X$Each entity should have an effective succession plan in place to avoid, inter alia, key person risk.$X$,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
