INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$becc7ade-f0a0-84f1-42fe-8863d1f7ea4e$X$,$X$17280db9-4151-d025-99ef-310907a9ed4c$X$,$X$Section 8 Record Keeping and Accounting Records Chapter 5 Appendix 1 of the COB presents a table set$X$,$X$Annual Review Record Keeping Policy
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$9a5040c1-7370-f08a-345b-893c2e6eac71$X$,$X$b84e7998-42fa-a0b7-ef8f-a16d20aca9fd$X$,$X$Section 2 - Competence$X$,$X$Monthly Continuous Professional Development Courses for Directors and Approved Persons$X$,$X$3.2.1: A person shall demonstrate and provide reasonable assurance to the satisfaction of the Authority of having an appropriate level of knowledge, professional expertise and experience.
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$64c675b4-4df9-7a8f-ef40-0b91577d80c9$X$,$X$4e761950-e854-dc86-a334-be2004426dc6$X$,$X$Art 5 (4) -$X$,$X$Monthly Continuous Professional Development Courses for Directors and Approved Persons$X$,$X$Members of the management body of the financial entity shall actively keep up to date with sufficient knowledge and skills to understand and assess ICT risk and its impact on the operations of the financial entity, including by following specific training on a regular basis, commensurate to the ICT risk being managed.$X$,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$5b10d137-6cd6-ae76-b384-cf5affcdf7d1$X$,$X$53e86238-2813-c401-9ec7-068c0420db82$X$,$X$General$X$,$X$Monthly Continuous Professional Development Courses for Directors and Approved Persons$X$,$X$(DB Path: Deriv_Compliance_DIEL [Malta]/Data Protection/IDPC Submissions/20230824 Questionaire on the designation and position of the data protection officer)$X$,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$2ab8b35d-104c-3eb9-215d-4436909cf186$X$,$X$2f78fca5-e06e-4b86-ce96-27c9de424c9b$X$,$X$Section 2.1.3 Appointment and Succession, Article 2.1.3.1.2$X$,$X$Annual Fit & Proper Declaration$X$,$X$"Authorised Entities should ensure that the Board is composed of persons who are fit and proper. Entities are expected to perform their own assessment and due diligence prior to proposing such person, and on a regular basis thereafter, to ensure these individuals are, in the entity’s opinion, fit and proper persons".$X$,2,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$1eb2b7cf-b884-0fbb-3a91-5321966e2f41$X$,$X$b8b029b4-9da5-271c-7317-6ce38ff1dd0e$X$,$X$General$X$,$X$Annual Monitoring Due Diligence Reports (Management Body, Key Function Holders and Shareholders up to the UBO)$X$,$X$Hence, the yearly due diligence reports are duly in place in alignment.$X$,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$70a4d756-2f3a-e729-c5b1-2b4473e33ed2$X$,$X$17280db9-4151-d025-99ef-310907a9ed4c$X$,$X$R1-1.6.9$X$,$X$Monthly ESMA & MFSA Publications Monitoring$X$,$X$Without prejudice to these Rules, Licence Holders shall make reference to and where applicable comply with the provisions of the IFR, CRR, MiFIR, SFDR, Taxonomy, as well as national legislation transposing the IFD, CRD, and MiFID II. Licence Holders shall also make reference and where applicable comply with Rules and Regulations issued under the aforesaid national legislation. The Licence Holder shall also refer to the Annexes, Guidelines, Circulars, and any other publication to the Authority where relevant and necessary.IS (Part BI) Rulebook Section Risk$X$,7,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$700bf54f-7b6b-82e2-f556-943bb9767e26$X$,$X$eb72d3b1-2207-6e64-2b57-482c3d0ff2e1$X$,$X$General$X$,$X$Quarterly Monitoring of Onboarded Affiliates$X$,$X$Third parties, also referred to in the industry as introducing brokers or affiliates, (“third parties”), are widely used to facilitate the cross border distribution of CFDs and other speculative products. Third parties have been observed carrying out a wide range of promotional, marketing and client services activities on behalf of investment firms. In many cases these activities overlap and it can be difficult to distinguish between the marketing of the firm/brand, the provision of customer support services and the provision of investment services. Given the extensive use of third parties in the industry, it is critical that authorised firms have robust controls in place to ensure the effective oversight of these relationships.$X$,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$d2f2f7ca-1de5-eab9-8648-b0a52041540a$X$,$X$7cfca796-15d4-b4d6-b3f9-3b519191d1af$X$,$X$General$X$,$X$Quarterly Monitoring of Onboarded Affiliates$X$,$X$Considering that firms select the affiliates and reach agreements with them, it is only logical that the firms are and remain responsible for how the selected affiliates communicate about the firm and the financial services. Firms should therefore monitor the marketing communications and practices of the affiliates they have partnered with in order to ensure compliance with the applicable requirements. 
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$50d21de4-148d-81d7-edf8-a9361de7d8a0$X$,$X$3cceca1e-e9b4-9cef-bf34-c9f6c15867c6$X$,$X$Section 3.1.2 of Safeguarding of Clients' Assets Policy$X$,$X$Annual BOD Approval of % of Clients Monies in each Bank$X$,$X$Following the annual checks (i.e. Risk Assessments) and findings by the Compliance function, the BOD will reassess the amounts in percentage to be held in each credit institution (if and where necessary).$X$,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$df1f3ef3-87a9-f2a8-f99a-92dc04167bb2$X$,$X$17280db9-4151-d025-99ef-310907a9ed4c$X$,$X$General$X$,$X$Annual Review Safeguarding of Clients' Assets Policy
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$0cb10f2a-3d34-ba8e-9179-f0dbd71bad21$X$,$X$33f23ab5-9218-84d8-be6d-0882ce4e7562$X$,$X$Section 6. Annual Review and Declaration$X$,$X$Annual Review Safeguarding of Clients' Assets Policy
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$d915e564-1ae9-bd13-59f6-66c98e9ca5ab$X$,$X$9bd12d1b-ad9b-830e-b6f3-9aae6c8fcfc6$X$,$X$Article (5)$X$,$X$Monthly Monitoring Safeguarding Client Assets$X$,$X$"The  subject  person  shall  conduct,  on  a  regular  basis, reconciliations between its records and accounts and those of any third parties with whom customer’s instruments and money have been deposited in accordance with regulations 8 and 9".$X$,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$1b80ba64-b5d7-80c1-7b36-0203a87cf6f7$X$,$X$db24efd1-0bed-9a44-bfc5-13357166fede$X$,$X$General$X$,$X$Monthly Monitoring Safeguarding Client Assets$X$,$X$In safeguarding clients' monies, the Company predominantly: 
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$96103dbe-4150-e522-6462-958f1a2936ce$X$,$X$cee40b3d-fb83-37a1-2355-848a41e5d946$X$,$X$General$X$,$X$Monthly Monitoring Safeguarding Client Assets$X$,$X$In addition to the procedures outlined above, the Compliance Officer routinely conducts monthly checks on the segregation of clients' funds. The objective of these checks is to verify the accuracy and integrity of the client funds recorded within the Company's systems in comparison to their corresponding balances in the client monies bank accounts. In the event of any discrepancies identified during these checks, requisite transfers are promptly initiated. Any identified irregularities are subsequently reported to the relevant department or team for further investigation and resolution.$X$,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$71ac3c0b-6dbd-7a14-182f-2957cead37f7$X$,$X$e78a494e-9402-7a77-abf0-db8ebc8d2b69$X$,$X$General$X$,$X$Monthly Monitoring Safeguarding Client Assets$X$,$X$Due to the fluctuating value of open trading positions, the Company periodically
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$d1deaebc-ee36-edda-2f84-ebf60eaa78ca$X$,$X$33f23ab5-9218-84d8-be6d-0882ce4e7562$X$,$X$Section 4.3 Compliance Officer Checks$X$,$X$Monthly Clients' Monies % in Banks Reconciliation$X$,$X$In addition to the procedures outlined above, the Compliance Officer routinely conducts monthly
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$962e97f1-79c2-3bee-8f3e-71497b00e276$X$,$X$a3b2f1cf-763c-8574-d698-030539a59207$X$,$X$General$X$,$X$Annual Outsourcing Declaration on Safeguarding of Clients Assets Policy$X$,$X$When the policy is approved by the Board, the Compliance Officer will ensure that an annual declaration is collected from the outsourcing service provider provisioning the function of accounting and payments. The declaration shall confirm that the policy has been read and understood by all relevant staff of the outsourcing service provider.$X$,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$5ea4ea32-19c9-de19-b77c-ecb102d6a120$X$,$X$1d9e968a-67e1-94f5-419a-dcc4b96de175$X$,$X$Chapter 4, Section 6: Complaint Handling by Regulated Persons, Complaints Management Policy, R.4.6.4$X$,$X$Annual Review Complaints Management Policy
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$1ba3717e-3592-da3b-556f-6cf2a8f1b307$X$,$X$2b649e78-b1e1-7520-93ef-ceab211944b7$X$,$X$Section 10$X$,$X$Annual Review Complaints Management Policy
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$96446c6d-00b5-97c5-7e73-12a588ca82e9$X$,$X$26539e8b-0dc4-69fb-aa13-ec6e359ed253$X$,$X$General$X$,$X$Annual Review Complaints Management Policy
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$bc8eb7fe-47cf-f5ec-22c3-e808adcca60c$X$,$X$17280db9-4151-d025-99ef-310907a9ed4c$X$,$X$Section 17 Arbiter R1-1.17.1$X$,$X$Annual Review Complaints Management Procedure
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$099f9d1c-4dd6-580f-543b-577ca4523737$X$,$X$2b649e78-b1e1-7520-93ef-ceab211944b7$X$,$X$Section 6.4  Conduct of Business Rulebook, Chapter 4, Section 6: Complaint Handling by Regulated Per$X$,$X$Quarterly Monitoring of Complaints and Complaints Register$X$,$X$Regulated Persons shall register any complaints it receives in an appropriate manner, (for example through a secure electronic register) as soon as these are received together with any action taken with respect to such complaints. The MFSA may at any time require the register to be produced for its review.$X$,1,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$34f74251-be55-0559-d244-951dfc517fb4$X$,$X$b563be02-53f7-2189-1fa9-0a0683b17256$X$,$X$General$X$,$X$Quarterly Monitoring of Complaints and Complaints Register$X$,$X$Without prejudice to the provisions of the Data Protection Act (Cap. 560) and any applicable provisions of Maltese law relating to record keeping, it is considered best practice for:
(a) the register of complaints held by a Regulated Person to contain all the necessary information on the complaints, including;
(i) the subject of the complaint;
(ii) data on the complainant;
(iii) date of receiving and answering the complaint;
(iv) result/outcome of the complaints handling procedure;
(v) class of business or Financial Instrument, as applicable to which the complaint relates;$X$,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$cf473e4e-034e-eb0a-5d17-db6beaafc971$X$,$X$171e74b8-99b4-3911-957a-1b1192d921bf$X$,$X$R.4.6.8$X$,$X$Quarterly Monitoring of Complaints and Complaints Register$X$,$X$Regulated Persons shall analyse on an on-going basis, complaints handling data to ensure that they identify and address any recurring or systemic problems, and potential legal and operational risks. In this respect, the Regulated Person shall grant to the compliance function access to all the Client complaints it receives and shall also ensure that its compliance function:
(e) has a role in monitoring the operation of the complaints process; and
(f) considers complaints as a source of relevant information in the context of the said function’s general monitoring responsibilities. For the avoidance of doubt, this does not require the compliance function to have a role in determining the outcome of complaints.$X$,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$896257ad-33f3-6bbc-2fd8-d183ab3bd111$X$,$X$2b649e78-b1e1-7520-93ef-ceab211944b7$X$,$X$Section 9$X$,$X$Annual Monitoring Complaints Handling Process Training$X$,$X$The Company shall provide adequate training sessions, at staff onboarding and there onwards at least on an annual basis, to remind all relevant staff participating in complaint handling of their responsibilities and to make them aware of any changes in the complaints handling procedures of the Company.$X$,2,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$e139f002-f92d-52dc-27c4-269047ca5103$X$,$X$1d9e968a-67e1-94f5-419a-dcc4b96de175$X$,$X$Section 6: Complaint Handling by Regulated Persons:
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$c9d0d315-b1de-b924-7ecf-366839bed772$X$,$X$ca655305-9ce7-ed95-a98c-9b046638ba30$X$,$X$General$X$,$X$Annual Monitoring Complaints Handling Process Training$X$,$X$(h) internal reporting, follow up and monitoring of compliance with the complaints management policy.$X$,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$2bf2a7f2-b664-6e29-e8e5-1c4a65a8721c$X$,$X$17280db9-4151-d025-99ef-310907a9ed4c$X$,$X$Sub-Section 5 Internal Audit, Article R1-1.5.5.1 (i)$X$,$X$Annual Internal Audit Plan$X$,$X$The Licence Holder shall establish and maintain an internal audit function which is separate and independent from the other functions and activities of the Licence Holder and which has the following responsibilities:
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$524dbc17-8979-edb4-aa1a-ec1d06ed65c0$X$,$X$4e761950-e854-dc86-a334-be2004426dc6$X$,$X$Art 5 (2)$X$,$X$Annual Internal Audit Plan$X$,$X$The management body of the financial entity shall define, approve, oversee and be responsible for the implementation of all arrangements related to the ICT risk management framework referred to in Article 6(1).
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$6330cf75-46f3-b446-f8b8-d7b6349b6144$X$,$X$caf82fec-de84-fb3c-0bbf-a5e0cfae2d4f$X$,$X$Article 17 ICT-related incident management process$X$,$X$Annual Review Reporting of Major ICT Incidents, Significant Cyber Threats, and Information-Sharing Policy and Procedure
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$18e2c557-66e8-d5c5-a7d0-f3295b55c48e$X$,$X$1aa32211-b160-532d-483e-54abcd3957e0$X$,$X$Article 19 Reporting of major ICT-related incidents and voluntary notification of significant cyber$X$,$X$Annual Review Reporting of Major ICT Incidents, Significant Cyber Threats, and Information-Sharing Policy and Procedure
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$003c4069-f5ad-f79f-e29a-fc7bdc663773$X$,$X$c86ecbeb-58cc-f0a7-66dd-83b0f6711052$X$,$X$Article 45 Information-sharing arrangements on cyber threat information and intelligence$X$,$X$Annual Review Reporting of Major ICT Incidents, Significant Cyber Threats, and Information-Sharing Policy and Procedure
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$9e62ccb4-6197-05ba-9a13-a5e9877b89e4$X$,$X$b6b30538-d2c9-26c9-a344-1630bf7176e0$X$,$X$Article 17 ICT-related incident management process$X$,$X$Monthly Monitoring Incidents Register$X$,$X$2.Financial entities shall record all ICT-related incidents and significant cyber threats. Financial entities shall establish appropriate procedures and processes to ensure a consistent and integrated monitoring, handling and follow-up of ICT related incidents, to ensure that root causes are identified, documented and addressed in order to prevent the occurrence of such incidents.$X$,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$8f0e782c-35c9-d414-8e40-bb8dc80de544$X$,$X$68587f5d-d916-14e6-bda6-8919934a6302$X$,$X$Article 11.
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$b275d711-396d-84f9-067f-5e76c6e1da16$X$,$X$f5b2e511-2263-a77e-6f50-0a63bb961737$X$,$X$General$X$,$X$Monthly Re-Occurrence Incident Check$X$,$X$(https://eur-lex.europa.eu/eli/reg_del/2024/1772/oj/eng)$X$,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$b5085ce1-b418-a150-06f7-33cf3485f533$X$,$X$b8bb3adf-bbff-8c75-49ec-8645c6ee941e$X$,$X$General$X$,$X$Monthly Re-Occurrence Incident Check$X$,$X$An incident shall be considered a major incident for the purposes of Article 19(1) of Regulation (EU) 2022/2554 where it has affected critical services as referred to in Article 6 and where either of the following conditions is fulfilled:
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$38daf935-3727-5f78-95d3-617d5f165548$X$,$X$f64e273d-caf7-900a-b7c1-15625685ce35$X$,$X$Article 20, first subparagraph, point (b) of Regulation (EU) 2022/2554;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$f8d42ee5-69cb-6778-6148-13a2a583bf3f$X$,$X$4e761950-e854-dc86-a334-be2004426dc6$X$,$X$Article 8$X$,$X$Monthly Monitoring of Cyber Threat Register$X$,$X$2.   Financial entities shall, on a continuous basis, identify all sources of ICT risk, in particular the risk exposure to and from other financial entities, and$X$,2,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$525cc7db-4cae-ce0c-e951-eeee04e22863$X$,$X$145cc37b-25c5-9177-ebfd-b2d05935f76d$X$,$X$General$X$,$X$Monthly Monitoring of Cyber Threat Register$X$,$X$and ICT vulnerabilities relevant to their ICT supported business functions, information assets and ICT assets. Financial entities shall review on a regular basis, and at least yearly, the risk scenarios impacting them.$X$,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$70137f69-4a0c-da00-df89-21af21e552e1$X$,$X$4e761950-e854-dc86-a334-be2004426dc6$X$,$X$Aritcle 17$X$,$X$Monthly Monitoring of Cyber Threat Register$X$,$X$2. Financial entities shall record all ICT-related incidents and significant cyber threats.$X$,3,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$3e6b3b88-9a39-df01-ef5a-c723792212eb$X$,$X$4e761950-e854-dc86-a334-be2004426dc6$X$,$X$Aritcle 19$X$,$X$Monthly Monitoring of Cyber Threat Register$X$,$X$2.   Financial entities may, on a voluntary basis, notify significant cyber threats to the relevant competent authority when they deem the threat to be of relevance to the financial system, service users or clients. The relevant competent authority may provide such information to other relevant authorities referred to in paragraph 6.$X$,4,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$2611481c-5e0f-3108-547b-243eca8985d1$X$,$X$17280db9-4151-d025-99ef-310907a9ed4c$X$,$X$R1-1.11.5$X$,$X$Annual Submission of Recovery Plan$X$,$X$Licence Holders which are subject to SL 330.09 shall submit to the Authority anoriginal copy of the Recovery Plan by not later than 1 June of each year.
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$49ddd64d-defa-60fc-6074-9a248d447aeb$X$,$X$1e261f45-c3e5-0038-2e2e-c53ecec9e9cf$X$,$X$R1-1.11.1$X$,$X$Annual Review Recovery Plan
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$a2832ee4-d799-0fb5-9b92-e77bdc190836$X$,$X$c6a9be42-656f-5db1-fd13-c7c725895e63$X$,$X$General$X$,$X$Annual Review Recovery Plan
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$de9aab88-5b31-46aa-f988-14cdf10c3794$X$,$X$17280db9-4151-d025-99ef-310907a9ed4c$X$,$X$R1-1.7.1 (xxi)$X$,$X$Monthly Check of Liquidity Providers Active List$X$,$X$The Licence Holder shall inform the MFSA in writing on investmentfirms@mfsa.mt, of:
(xxi) Changes to counterparties/ liquidity providers where the Licence Holder offers contracts for differences (CFDs) and/or rolling spot forex contracts and/or binary options trading.$X$,12,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$b5ec880d-1a9b-6edb-3d46-8992b4b1f855$X$,$X$e939fe7f-d9ca-1a03-bdd3-99dd05300e02$X$,$X$General$X$,$X$Monthly Check of Liquidity Providers Active List$X$,$X$8. Any changes to counterparties/ liquidity providers post-licensing shall be notified to the Authority in advance of the change.$X$,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$207967c6-6c33-3dc4-f626-96424a7541f0$X$,$X$78e804ac-d97a-8503-c92a-be30d85469b7$X$,$X$Section 4$X$,$X$Annual Review Staff Testing Policy
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$ebe147ed-fb5e-6ae1-85e6-a60330e64c73$X$,$X$11ec01a9-8a10-7e3f-e7ce-d36ebad25ae5$X$,$X$General$X$,$X$Annual Review Staff Testing Policy
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$43010521-28ac-9e15-a2cb-ed21ed392bf1$X$,$X$78e804ac-d97a-8503-c92a-be30d85469b7$X$,$X$Section 3 Monitoring & Oversight$X$,$X$Quarterly Monitoring of Staff Test Accounts$X$,$X$To ensure that the policy is followed in practice, the Company performs periodic checks to ensure that no staff are dealing on the Company’s platforms for their own personal benefit. Further information on how such accounts is monitored can be found in the Prevention of Market Abuse Procedures document.$X$,1,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$e8c739b5-f5a0-4859-d972-0cae66d800fa$X$,$X$eb6ef328-9e20-d64b-1d94-412845c0f9f3$X$,$X$General$X$,$X$Quarterly Monitoring of Staff Test Accounts$X$,$X$Every quarter, a full report of all account sign-ups is extracted to review any test accounts created within that period and whether they are all marked as internal test accounts in back-office.$X$,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$badc83ac-b92a-ca24-c003-eda13263053a$X$,$X$fd11198b-63cb-6f11-1c4b-4a3781515e64$X$,$X$General$X$,$X$Quarterly Monitoring of Staff Test Accounts$X$,$X$The periodic data on staff test accounts is reviewed to ensure that all accounts which contain a balance were funded by the Company.$X$,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$fbdae41e-fe61-1531-2b70-b9f27071ce46$X$,$X$1fcf40b0-2fb2-323a-c8e9-2e5149420669$X$,$X$General$X$,$X$Quarterly Monitoring of Staff Test Accounts$X$,$X$Should any withdrawal requests be made by members of staff, these will be checked thoroughly, ensuring further that staff are not dealing on the Company’s platforms for any personal interest and in conflict with the Company’s policies."$X$,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$1e1d2cb2-85ad-a572-08b5-92f862256072$X$,$X$096668f5-cfb5-7574-4df0-9e6981345667$X$,$X$R.3.6$X$,$X$Annual Review Conflicts of Interest Policy with Annexes; Remuneration Policy & Inducements Policy
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$15311612-e05a-954a-9603-c2d0a515a295$X$,$X$0d102f2e-7d0a-80b2-af89-3282fcbaa3ee$X$,$X$Section 7 Training$X$,$X$Annual Training on Conflicts of Interest$X$,$X$The Company recognizes that ongoing and effective training is crucial for ensuring that all relevant staff understand their roles in managing conflicts of interest and maintaining the highest standards of conduct. The Company shall provide regular mandatory training on this Conflict-of-Interest Policy. The training aims to ensure that all staff are fully aware of their obligations regarding conflicts of interest. This training will be conducted at least annually and ad hoc as and when necessary. New employees will undergo induction training that includes a thorough explanation of the Conflict-of-Interest Policy. The Compliance Function will monitor and maintain records of all training activities, including the dates of training, the content covered, and the names of staff who have attended. The Company expects its representatives to act with honesty and integrity.$X$,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$edabb4af-5e36-a25d-bf96-f313b8c1a88f$X$,$X$1d9e968a-67e1-94f5-419a-dcc4b96de175$X$,$X$Section 2 Client Categorisation, General Rules Article R.4.2.2$X$,$X$Annual Review Client Categorisation Policy$X$,$X$A Regulated Person shall, before providing a Service within the meaning of points (i), (ii) and (v) of the definition of Service in the Glossary to these Rules, classify a Client to whom the Service is to be offered as a Professional Client, as a Retail Client or as an Eligible Counterparty.$X$,5,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$93ee66f7-4fc4-90af-f592-5089982da239$X$,$X$2f78fca5-e06e-4b86-ce96-27c9de424c9b$X$,$X$Section 2.1.2.2 Supporting Provisions, Article 2.1.2.2.4$X$,$X$Annual Monitoring Individual Suitability of the Board and Key Persons$X$,$X$An assessment or re-assessment of the collective suitability of the Board should be carried out on a regular basis, particularly in the case of events that can materially affect such collective suitability.$X$,3,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$0013db2a-a3f0-98ef-0ebe-60b0c98a23b2$X$,$X$1cbcb595-f9f5-356d-59ee-5d7d7a8acc68$X$,$X$General$X$,$X$Annual Monitoring Individual Suitability of the Board and Key Persons$X$,$X$Authorised Entities should ensure that the Board is composed of persons who are fit and proper. Entities are expected to perform their own assessment and due diligence prior to proposing such person, and on a regular basis thereafter, to ensure these individuals are, in the entity’s opinion, fit and proper persons.
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$45320dfc-0b33-c7a5-1866-182dff8250db$X$,$X$bc18d9a4-bef2-f0d6-abe1-f0e5e1e285e5$X$,$X$Section 2 Competence, Article 3.2.7$X$,$X$Annual Monitoring Individual Suitability of the Board and Key Persons$X$,$X$Members of the management body of an applicant or of a licence holder shall be able to demonstrate, both collectively and individually, that they are sufficiently competent to perform their role within an authorised entity.$X$,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$96122e98-2666-221a-e5bf-12028a69d67d$X$,$X$5e82ca36-e6d7-c6e0-33bf-e650a2f0f55b$X$,$X$General$X$,$X$Annual Monitoring Collective Suitability of the Board$X$,$X$These Guidelines specify further, in accordance with Article 91(12) of Directive 2013/36/EU2 and Article 9(1) second subparagraph of Directive 2014/65/EU3, the requirements regarding the suitability of members of the management body in particular, the notions of sufficient time commitment; honesty, integrity and independence of mind of a member of the management body; adequate collective knowledge, skills and experience of the management body; and adequate human and financial resources devoted to the induction and training of such members. The notion of diversity to be taken into account for the selection of members of the management body is also specified in accordance with the above-mentioned articles.$X$,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$d4107d4f-09e9-6245-5781-ff7e7e2a6477$X$,$X$8e34a184-da37-4aa9-518a-75111d1370d8$X$,$X$General$X$,$X$Annual Monitoring Collective Suitability of the Board$X$,$X$Institutions should take into account their size, their internal organisation and the nature, scale and complexity of their activities when developing and implementing policies and processes set out in these Guidelines. Significant institutions should have more sophisticated policies and processes, while in particular small and less complex institutions may implement simpler policies and processes. Institutions should note that the size or systemic importance of an institution may not, by itself, be indicative of the extent to which an institution is exposed to risks. Those policies and processes should, however, ensure compliance with the criteria specified in these Guidelines to assess the suitability of members of the management body and key function holders and the elements to take diversity into account when recruiting members to the management body and to provide sufficient resources for their induction and training.$X$,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$05b00432-2662-a9f5-cbd5-87820cdfc709$X$,$X$8a37612f-b023-9ece-3927-7be88595f1ed$X$,$X$General$X$,$X$Annual Monitoring Collective Suitability of the Board$X$,$X$Institutions should ensure, in fulfilling the obligation set out in Article 91(7) of Directive 2013/36/EU, that at all times the management body collectively possesses adequate knowledge, skills and experience to be able to understand the institution’s activities, including the main risks. Notwithstanding the experience, knowledge and skills requirement for each member of the management body, institutions should ensure that the overall composition of the management body reflects an adequately broad range of knowledge, skills and experience to understand the institution’s activities, including main risks.$X$,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$682b20ac-22f8-988e-98e1-57657f4d682c$X$,$X$2f78fca5-e06e-4b86-ce96-27c9de424c9b$X$,$X$Section 2.1.2 Structure and Composition of the Board of Directors, Sub-Section 2.1.2.2 Supporting Pr$X$,$X$Annual Review of PGWG Terms of Reference$X$,$X$Boards are encouraged to set up Committees to assist them in adequately carrying out their duties. Where Committees are set up: [i] their composition should be set up in accordance with the criteria outlined for the Board’s composition; [ii] they should be provided with any relevant information in a timely manner; and [iii] the Board should establish and approve clear terms of reference of the Committee.$X$,4,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$718f2156-0f7c-2388-9885-229dba39eaa4$X$,$X$a9a02526-6729-cbb8-0cc2-6e5fa0c5a9f7$X$,$X$General$X$,$X$Annual Review of PGWG Terms of Reference$X$,NULL,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$aa78fafd-6a4f-8927-2267-fcaf01b9dd5b$X$,$X$22a80343-6603-4d0f-a7b8-e73e5c801f6a$X$,$X$Article R.5.6$X$,$X$Annual Review Best Execution Policy
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$fff0121c-578d-66e3-2657-75a4033a908a$X$,$X$22486804-b90f-28d7-4edb-e22477bf7211$X$,$X$Article R.5.3$X$,$X$Annual Review Best Execution Policy
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$30dda26b-12b7-b664-30f8-3f076e4c7e1f$X$,$X$c5366ec4-e256-dd2d-a70b-f7c503c393fd$X$,$X$R.4.1.45$X$,$X$Annual Best Execution Monitoring vs Slippage$X$,$X$Regulated Persons are prohibited from engaging in any manipulative acts or practices regarding the price of any underlying Financial Instrument. For this purpose, Regulated Persons shall implement procedures which would prohibit them from cheating, defrauding, or deceiving or attempting to cheat, defraud or deceive any other person. Such procedures shall include the establishment of 
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$37b679c1-2815-1c97-c372-7486cc19499a$X$,$X$400c0d4b-ae8a-2067-2a75-241bd5886dff$X$,$X$Sub-Section 2 The Outsourcing Policy, Article R1-1.15.2.1$X$,$X$Annual Review Outsourcing Policy
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$4302083c-7cc5-ce9e-b076-b6dbe5007767$X$,$X$400c0d4b-ae8a-2067-2a75-241bd5886dff$X$,$X$Sub-Section 3 The Outsourcing Contract, R1-1.15.3.2$X$,$X$Annual Outsourcing Providers Performance Review$X$,$X$The Licence Holder shall ensure that the outsourcing contract includes:
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$77857d0b-ce9b-791c-060c-a6a42622b934$X$,$X$1ad052a3-2647-0cc4-460d-b1e0bf0028f0$X$,$X$Section 3.5.1. Ongoing Monitoring$X$,$X$Annual Outsourcing Providers Performance Review$X$,$X$The Company shall ensure that it conducts on-going monitoring on the performance of the service providers regarding all outsourcing arrangements following a risk-based approach, considering the principle of proportionality, and with the focus being on critical or important functions, while ensuring the availability, integrity and security of data and information.
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$a88680f1-5422-47ca-09d2-3149cf409383$X$,$X$649b4a96-7806-70d5-5c79-c762f9762c93$X$,$X$General$X$,$X$Annual Outsourcing Providers Performance Review$X$,$X$Section 14 - Oversight of outsourced functions: Institutions and payment institutions should ensure, on an ongoing basis, that outsourcing arrangements, with the main focus being on outsourced critical or important functions, meet appropriate performance and quality standards in line with their policies by:
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$97d18d6d-4c2e-5364-7344-fb5322dbe4b4$X$,$X$1749b0ca-2aae-2a71-c9b8-06d5b8a55cc7$X$,$X$General$X$,$X$Annual Outsourcing Providers Performance Review$X$,$X$:  intragroup outsourcing is subject to the same regulatory framework as outsourcing to service providers outside the group. Intragroup outsourcing is not necessarily less risky than outsourcing to an entity outside the group. In particular, with regard to intragroup outsourcing, institutions and payment institutions need to take into account conflicts of interest that may be caused by outsourcing arrangements, e.g. between different entities within the scope of consolidation.$X$,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$4881efc9-6e1d-0954-6bea-658f5774ea1c$X$,$X$6401a4c1-bc60-b291-52a9-e098eca5c865$X$,$X$Sub-Section 3 Compliance Function, Article R1-1.5.3.1$X$,$X$Annual Compliance Function Policy Review$X$,$X$The Licence Holder shall establish and maintain a permanent and effective compliance function which operates independently and which has the following responsibilities:
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$9d36428e-a62e-09ac-1f78-1fbb968361a9$X$,$X$110dd4c9-0c43-93a3-2fe0-506e4bc247f0$X$,$X$General$X$,$X$Annual Compliance Function Policy Review$X$,$X$57. The responsibilities and competences as well as the authority of the compliance function should be set out in a ‘compliance policy’ or other general policies or internal rules that take account of the scope and nature of the firm’s investment services and activities. This should include information on the monitoring programme and the reporting duties of the compliance function as well as information on the compliance function’s risk-based approach to monitoring activities. Relevant amendments to the applicable requirements should be reflected promptly by adapting these policies/rules.$X$,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$d552138a-bea7-9272-b3a2-15460a9b164a$X$,$X$d6f945c2-298c-52a6-fac3-0aac0915b762$X$,$X$General$X$,$X$Annual Compliance Function Policy Review$X$,$X$The Compliance Function Policy shall be reviewed, updated, and approved by the Board of Directors at least annually, or as needed, to ensure its relevance and alignment with applicable regulations, guidelines, and internal governance requirements.$X$,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$de18ed02-dbf4-7616-28e2-f03cd6273e97$X$,$X$ccaf63d1-5a05-ce59-ec1d-246cc513b385$X$,$X$Section 10: Business Continuity Process, Article R1-1.10.1$X$,$X$Annual ICT Business Continuity Policy, with Annex; Environmental, Health and Geopolitical Disruptions
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$82fbbde4-74d3-b085-3b16-489bacac1526$X$,$X$bbf8bfce-73d8-ca5a-2f5a-36a6a968d6a5$X$,$X$Section 3.4 Information Security, Subsection 3.4.1 Information Security Policy$X$,$X$Annual Information Security Policy and Annexes 
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$8d9d5eb1-0c82-0be2-ffeb-ea0bc7159e7d$X$,$X$5daa0a7e-2646-5ebc-7776-25e7b47a8d68$X$,$X$Section 3, Sub-Section 3.6 Security Awareness States$X$,$X$Quarterly Security Awareness Phishing Campaigns Monitoring$X$,$X$The Company's Security Team conducts regular employee awareness activities to all employees such as:
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$9ae2c84b-1dbd-8c75-435c-ed7f4228b743$X$,$X$add9ba24-d266-4b80-906d-f05299a16b98$X$,$X$General$X$,$X$Annual Screening Manual Review$X$,$X$, the Authority provided feedback on the Company's Liquidity Providers, particularly regarding due diligence and performance. While the Authority did not explicitly request the Company to submit its Screening Manual, the Company maintains and updates one annually.$X$,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$3263dd5b-2daa-c9bf-52c1-cecc23c0a82a$X$,$X$4105148f-1c1a-ddd6-fdb6-661c07c35ed6$X$,$X$Article 37 - 39$X$,$X$Annual Review of DPO Appointment & Registration$X$,$X$sets out requirement for appointing a DPO as well as the DPO's position and tasks$X$,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$6c69a7d3-c90a-19bb-c1e1-dd6354edf272$X$,$X$4105148f-1c1a-ddd6-fdb6-661c07c35ed6$X$,$X$Article 24$X$,$X$Annual Review Data Protection Policy$X$,$X$: Sets out responsibility of the Controller. Controllers must implement appropriate technical and organizational measures to ensure and demonstrate compliance with GDPR. This includes policies, procedures, and other documentation to meet data protection principles.$X$,1,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$bf14fa16-333f-e305-36b3-48da6ebf1251$X$,$X$4105148f-1c1a-ddd6-fdb6-661c07c35ed6$X$,$X$Article 32$X$,$X$Annual Review Data Breach Procedure$X$,$X$Organizations must implement appropriate technical and organizational measures to ensure the ongoing confidentiality, integrity, and availability of personal data. This includes measures to protect against breaches and procedures for addressing breaches when they occur.$X$,2,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$43bf6050-9298-14e4-7737-0b58158774d6$X$,$X$4105148f-1c1a-ddd6-fdb6-661c07c35ed6$X$,$X$Article 12 - 15$X$,$X$Quarterly Review Subject Access Requests Log$X$,$X$The GDPR places significant emphasis on data subject rights, including the right of access as outlined in Articles 12 and 15. To demonstrate compliance with these rights and the related obligations, organizations must have appropriate measures—such as maintaining a log—to track and document requests.$X$,3,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$19cae582-660f-09c0-ba50-f98252b45fd1$X$,$X$4105148f-1c1a-ddd6-fdb6-661c07c35ed6$X$,$X$Article 12, 13, and 14$X$,$X$Annual Review Privacy Notices - Client, Employee, Job Applicant$X$,$X$: Requirement to provide clear, transparent, and accessible information to data subjects about how their personal data is collected, used, and processed.$X$,4,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$1f9e5fb9-7394-01c3-78e5-9a0ec835a06c$X$,$X$ee76af81-6020-a050-1d54-d5ca528b7b91$X$,$X$General$X$,$X$Quarterly Review of Data Protection Training Register$X$,$X$Data controllers are responsible for not only ensuring compliance with the GDPR but also demonstrating compliance with its principles (lawfulness, fairness, transparency, etc.).$X$,0,'ACTIVE',NOW(),NOW()) ON CONFLICT (id) DO NOTHING;
INSERT INTO "SourceItem" (id,"sourceId",reference,title,description,"sortOrder",status,"createdAt","updatedAt") VALUES ($X$2ff00aa9-a574-b135-e099-a80a18a237d7$X$,$X$7539e861-ae30-c69a-8211-4873218d4cd9$X$,$X$General$X$,$X$Annual Review of Market Abuse Policy
