INSERT INTO "Task" (id,name,description,"expectedOutcome",status,"riskRating",frequency,quarter,"dueDate","evidenceRequired","narrativeRequired","reviewRequired","clickupUrl","monitoringAreaId","taskTypeId","sourceId","sourceItemId","entityId","responsibleTeamId","recurrenceGroupId","recurrenceIndex","recurrenceTotalCount",version,"createdAt","updatedAt") VALUES ($X$09ba2241-49af-a10a-38ee-38f5e63a08b0$X$,$X$Quarterly Review of T&C Changes$X$,$X$The Compliance function shall perform a quarterly review of all cards raised in efforts to enact changes to any terms and conditions. This will serve as a check to ensure that any changes enacted are in alignment with the rules and regulations as required. This will be started in 2026.$X$,$X$Starting 2026$X$,'TO_DO'::"TaskStatus",'MEDIUM'::"RiskRating",'QUARTERLY'::"Frequency",$X$Q1$X$,'2025-12-31'::date,FALSE,TRUE,TRUE,$X$https://app.clickup.com/t/86c6e94wz$X$,(SELECT id FROM "MonitoringArea" WHERE name = $X$Disclosures$X$ LIMIT 1),(SELECT id FROM "TaskType" WHERE name = $X$Desk-Based Review$X$ LIMIT 1),$X$9ebc7955-ab3a-f0e2-ca2c-c563bba055ed$X$,$X$fe60240d-fe69-d709-8bd8-64e69988849a$X$,(SELECT id FROM "Entity" WHERE code = 'DIEL' LIMIT 1),(SELECT id FROM "Team" WHERE name = $X$Compliance Regulatory$X$ LIMIT 1),$X$e9b1ac13-c3b2-a15a-1ff6-b6134b53a099$X$,3,4,0,NOW(),NOW());
INSERT INTO "Task" (id,name,description,"expectedOutcome",status,"riskRating",frequency,quarter,"dueDate","evidenceRequired","narrativeRequired","reviewRequired","clickupUrl","monitoringAreaId","taskTypeId","sourceId","sourceItemId","entityId","responsibleTeamId","recurrenceGroupId","recurrenceIndex","recurrenceTotalCount",version,"createdAt","updatedAt") VALUES ($X$b5c0926c-dcff-0782-e5a1-760c978819cd$X$,$X$Annual Monitoring of High-Risk Group (Trading) Clients$X$,$X$The first line of defence implemented a structured approach to managing High-Risk Group Clients in May 2024. When a client account is moved from “default” to “high-risk,” a three-day prior notification is enforced. This approach ensures that the client is adequately  informed about changes to their account conditions, including adjustments to volume limits, swap rates, and spreads, as well as the removal of negative balance protection and stop-out compensation. Ultimately, since this is a change to the client’s trading specifications, the Compliance Function imposed the three day notification to ensure that the client has sufficient time to read, understand, and make a decision based on the disclosed information, considering the complexity of the product.$X$,$X$The expected outcome is that all relevant documentation with regards to Clients who were moved from default to high-risk is saved on the Company's internal repository accordingly on an annual basis. 
INSERT INTO "Task" (id,name,description,"expectedOutcome",status,"riskRating",frequency,quarter,"dueDate","evidenceRequired","narrativeRequired","reviewRequired","clickupUrl","monitoringAreaId","taskTypeId","sourceId","sourceItemId","entityId","responsibleTeamId","recurrenceGroupId","recurrenceIndex","recurrenceTotalCount",version,"createdAt","updatedAt") VALUES ($X$b13030db-39c1-c59b-87a5-3b42e5fc5c0e$X$,$X$Monthly Monitoring of Website Changes Request$X$,$X$Review the monthly ClickUp card containing requests for changes to the company's website. Ensure each change adheres to the standards outlined in the Website Disclosure Checklist. This includes verifying that all required disclosures are present, accurate, and compliant with regulatory and internal guidelines. Coordinate with relevant teams to address any discrepancies or ensure required updates are correctly implemented.$X$,$X$All website updates are monitored and validated to ensure ongoing compliance with the Website Disclosure Checklist. Any non-compliance or gaps identified are promptly addressed and rectified, ensuring the company’s website disclosures remain accurate, up-to-date, and aligned with regulatory requirements.$X$,'TO_DO'::"TaskStatus",'MEDIUM'::"RiskRating",'MONTHLY'::"Frequency",NULL,'2025-01-31'::date,FALSE,TRUE,TRUE,$X$https://app.clickup.com/t/86c4maj3c$X$,(SELECT id FROM "MonitoringArea" WHERE name = $X$Disclosures$X$ LIMIT 1),(SELECT id FROM "TaskType" WHERE name = $X$Desk-Based Review$X$ LIMIT 1),$X$9ebc7955-ab3a-f0e2-ca2c-c563bba055ed$X$,$X$fe60240d-fe69-d709-8bd8-64e69988849a$X$,(SELECT id FROM "Entity" WHERE code = 'DIEL' LIMIT 1),(SELECT id FROM "Team" WHERE name = $X$Compliance Regulatory$X$ LIMIT 1),$X$00f7c7fe-1b5b-2c7c-2f35-65345cf138db$X$,0,12,0,NOW(),NOW());
