INSERT INTO "Task" (id,name,description,"expectedOutcome",status,"riskRating",frequency,quarter,"dueDate","evidenceRequired","narrativeRequired","reviewRequired","clickupUrl","monitoringAreaId","taskTypeId","sourceId","sourceItemId","entityId","responsibleTeamId","recurrenceGroupId","recurrenceIndex","recurrenceTotalCount",version,"createdAt","updatedAt") VALUES ($X$39b83055-2032-2b48-8a3d-55e1575a9d0d$X$,$X$Monthly Check of Liquidity Providers Active List$X$,$X$On the 15th of each month, the full list of Deriv Investments (Europe) Ltd's Liquidity Providers (LPs) must be reviewed. Upon receiving the active LP list from the reporting team, the latest letter sent to the MFSA should be checked to confirm that no changes have occurred. Additionally, the terms in Article 8.1 of the Trading Terms (available on the website) must be reviewed to ensure that the LP list remains accurate and up to date.$X$,$X$To ensure the MFSA has the Company's most updated Liquidity Providers list and to ensure that the Trading Terms Liquidity Providers list is accurate and up-to-date.$X$,'TO_DO'::"TaskStatus",'MEDIUM'::"RiskRating",'MONTHLY'::"Frequency",$X$Q1$X$,'2025-01-15'::date,FALSE,TRUE,TRUE,$X$https://app.clickup.com/t/86bzvk4ax$X$,(SELECT id FROM "MonitoringArea" WHERE name = $X$Liquidity Providers$X$ LIMIT 1),(SELECT id FROM "TaskType" WHERE name = $X$Desk-Based Review$X$ LIMIT 1),$X$17280db9-4151-d025-99ef-310907a9ed4c$X$,$X$de9aab88-5b31-46aa-f988-14cdf10c3794$X$,(SELECT id FROM "Entity" WHERE code = 'DIEL' LIMIT 1),(SELECT id FROM "Team" WHERE name = $X$Compliance Regulatory$X$ LIMIT 1),$X$f52cb503-1968-c27e-2a22-48e0436c75ee$X$,0,12,0,NOW(),NOW());
