INSERT INTO "Task" (id,name,description,"expectedOutcome",status,"riskRating",frequency,quarter,"dueDate","evidenceRequired","narrativeRequired","reviewRequired","clickupUrl","monitoringAreaId","taskTypeId","sourceId","sourceItemId","entityId","responsibleTeamId","recurrenceGroupId","recurrenceIndex","recurrenceTotalCount",version,"createdAt","updatedAt") VALUES ($X$9dba5332-030c-9f92-7813-d07e20c1b66a$X$,$X$Quarterly Monitoring of Staff Test Accounts$X$,$X$The Company has implemented a Staff Dealing Policy that outlines the procedure staff members must follow when opening test accounts. According to this policy, staff members are prohibited from conducting any personal transactions on the Company’s platforms. However, they are permitted to create test accounts for the purpose of reviewing the performance of the Company's website and trading platforms, as well as for fulfilling their responsibilities related to monitoring, testing, and oversight. A desk-based review is conducted on a quarterly basis to ensure compliance with this policy and to confirm that no staff (Company and Group) members are engaging in personal dealings on the Company’s platforms.
