INSERT INTO "Task" (id,name,description,"expectedOutcome",status,"riskRating",frequency,quarter,"dueDate","evidenceRequired","narrativeRequired","reviewRequired","clickupUrl","monitoringAreaId","taskTypeId","sourceId","sourceItemId","entityId","responsibleTeamId","recurrenceGroupId","recurrenceIndex","recurrenceTotalCount",version,"createdAt","updatedAt") VALUES ($X$002b00a8-fc5c-9636-1a4a-8b8cde0cef4e$X$,$X$Annual Monitoring of Regulator's Registers for Passporting Countries$X$,$X$The Compliance team shall review cross border passporting information disclosed on https://deriv.com/eu/regulatory and ensure that; the pdf links on our website contain the latest up-to-date information.  If not, check the information on the respective member state's regulator's website and provide the updated information to the front-end team to update.  If the information on the member state's regulator's page is out of date update and send a notification to the MFSA who will in turn contact the member states' National Competent Authority.$X$,$X$Ensure that passporting details on the website and on the various countries' registers of regulators are up to date.$X$,'TO_DO'::"TaskStatus",'MEDIUM'::"RiskRating",'ANNUAL'::"Frequency",$X$Q1$X$,'2025-03-31'::date,FALSE,TRUE,TRUE,$X$https://app.clickup.com/t/32wp4xd$X$,(SELECT id FROM "MonitoringArea" WHERE name = $X$Passporting$X$ LIMIT 1),(SELECT id FROM "TaskType" WHERE name = $X$Desk-Based Review$X$ LIMIT 1),$X$0bdee6d5-e423-11ae-5337-f04664df4724$X$,$X$3c69a56b-81b2-8fe8-1b95-ba892793fead$X$,(SELECT id FROM "Entity" WHERE code = 'DIEL' LIMIT 1),(SELECT id FROM "Team" WHERE name = $X$Compliance Regulatory$X$ LIMIT 1),NULL,NULL,NULL,0,NOW(),NOW());
INSERT INTO "Task" (id,name,description,"expectedOutcome",status,"riskRating",frequency,quarter,"dueDate","evidenceRequired","narrativeRequired","reviewRequired","clickupUrl","monitoringAreaId","taskTypeId","sourceId","sourceItemId","entityId","responsibleTeamId","recurrenceGroupId","recurrenceIndex","recurrenceTotalCount",version,"createdAt","updatedAt") VALUES ($X$5a9398b4-ffa9-b7f2-0d29-9a69b9e9b51b$X$,$X$Annual Monitoring of Regulatory Framework for Passporting Countries$X$,$X$Periodic checks are performed on jurisdiction specific investor protection measures to ensure the Company applies the applicable measures where it provides its services.$X$,$X$Review each passporting countries measures and remediate should any actions are required.$X$,'TO_DO'::"TaskStatus",'MEDIUM'::"RiskRating",'ANNUAL'::"Frequency",$X$Q1$X$,'2025-03-31'::date,FALSE,TRUE,TRUE,$X$https://app.clickup.com/t/86bxa5upw$X$,(SELECT id FROM "MonitoringArea" WHERE name = $X$Passporting$X$ LIMIT 1),(SELECT id FROM "TaskType" WHERE name = $X$Desk-Based Review$X$ LIMIT 1),$X$0bdee6d5-e423-11ae-5337-f04664df4724$X$,$X$3c69a56b-81b2-8fe8-1b95-ba892793fead$X$,(SELECT id FROM "Entity" WHERE code = 'DIEL' LIMIT 1),(SELECT id FROM "Team" WHERE name = $X$Compliance Regulatory$X$ LIMIT 1),NULL,NULL,NULL,0,NOW(),NOW());
INSERT INTO "Task" (id,name,description,"expectedOutcome",status,"riskRating",frequency,quarter,"dueDate","evidenceRequired","narrativeRequired","reviewRequired","clickupUrl","monitoringAreaId","taskTypeId","sourceId","sourceItemId","entityId","responsibleTeamId","recurrenceGroupId","recurrenceIndex","recurrenceTotalCount",version,"createdAt","updatedAt") VALUES ($X$29d10621-6e78-2c27-d3a1-b08441693d50$X$,$X$Quarterly Active Passport Usage Check$X$,$X$Should the Company not actively use or stop using the Passport, for more than three months, the Company will notify the Authority accordingly as per the circular dated 26/04/2021.$X$,$X$To verify that the Passport (or passporting rights) remains active and is currently in use.
